        while lo <= hi:
            mid = (lo + hi) // 2
            candidate = self._new(self.im.quantize(mid, method, kmeans))
            converted = candidate.convert(self.mode)
            if mean_square_error(self, converted) <= error_threshold:
                best = candidate
                hi = mid - 1
            else:
                lo = mid + 1

        if best is not None:
            return best
        return self._new(self.im.quantize(colors, method, kmeans))
